[(0, 0, {
            'name': 'Sincronizar lote factura a venta',
            'model_id': ref('account.model_account_move_line'),
            'state': 'code',
            'code': "for line in records:
    if line.display_type not in (False, 'product'):
        continue
    if not line.move_id.is_sale_document(include_receipts=True):
        continue
    if line.move_id.state != 'draft':
        continue
    if len(line.sale_line_ids) != 1:
        continue
    sale_line = line.sale_line_ids[:1]
    if sale_line.lot_id != line.jh_sale_lot_id:
        sale_line.with_context(skip_invoice_lot_sync=True).write({'lot_id': line.jh_sale_lot_id.id or False})",
        })]
